	INSERT INTO public.location(
	restaurant_id, restaurant_description, restaurant_picture, restaurant_picture_embedded, city, country, restaurant_description_embedded)
	VALUES (1, 'Tucked away behind a nondescript ivy-covered gate, Velvet & Vine is an intimate sanctuary designed for the art of conversation. Bathed in the soft, amber glow of low-hanging crystal chandeliers and flickering candlelight, every table is a private alcove draped in deep crimson silk. Our menu is a curated symphony of shared plates—from delicate truffle-infused fondues to gold-leafed desserts—designed to be savored slowly. With the faint notes of a live cellist in the background and an extensive cellar of rare vintage champagnes, we provide the perfect stage for proposals, anniversaries, and the kind of nights you wish would never end.', 'pg_read_binary_file('data/restaurant.png')','[0.42760944,1.6370864,-3.313674,-0.94837743,1.2106725,-0.18783322,-0.95938385,-0.6516587,0.15119706,-0.98862195,0.4963007,1.8349118,0.6722435,1.7198207,0.13748689,-0.6156491,-0.035894275,-1.7284038,0.08780477,1.1671226,-0.36271608,1.0246282,-0.026575392,-0.53150505,0.31135213,-0.2196834,-0.051964827,2.0520587,-0.613772,-0.58561,-1.1444019,-0.72390807,-0.36935627,0.053978313,-0.8564855,-0.21741392,1.2764134,1.1172004,0.19173534,-0.65350074,0.51888,1.4726644,0.55515,-0.5983354,-0.34442976,0.07723631,0.1680603,0.33347854,-0.37476456,0.5227239,-0.5954905,1.2782556,-0.4083325,-2.2531888,-0.18358214,0.29445976,1.3025488,0.18801294,1.550101,-6.469441e-05,1.1467997,1.1629109,-0.27300844,1.0932022,1.1153448,-0.99495196,-0.90201926,0.6385959,-0.297301,-0.21521577,1.2202684,-0.94966096,0.80935,0.776365,-0.5159293,-0.9070655,0.24733613,0.43469533,-0.0031938446,0.20268884,0.14484689,0.23164658,0.21499869,-0.05945041,0.65445775,-0.43100306,-0.3894387,-1.1089991,-0.78307354,0.8153243,-0.13026224,0.123117365,-0.11833873,0.69981486,-1.3251683,0.766613,-0.73014146,1.0044237,-0.21378039,-0.14598617,0.20425318,0.4826183,0.8019011,-0.62271917,0.05109295,0.8856246,1.3978511,-0.00417343,-0.651509,-0.14174311,-0.63714546,0.3704401,-0.2933872,0.01031451,0.96082693,-0.5611994,1.0834558,-1.0295457,0.6463